import re

def scan_run_for_pii(run):
    pii_patterns = [
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
        r'\b\d{3}-?\d{2}-?\d{4}\b',
        r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b',
        r'\b[A-Z]\d[A-Z] \d[A-Z]\d \d[A-Z]\d\b'
    ]
    content = run.annotations[0].text.value if run.annotations else run.last_error
    for pattern in pii_patterns:
        if re.search(pattern, content, re.IGNORECASE):
            return {'detected': True, 'type': 'PII_FOUND'}
    return {'detected': False}

